<template>
    <div class="home">
        <p>什么也没有!!!</p>

        
    </div>
</template>
<script>
import { mapState } from 'vuex';
export default {
    computed: {
        ...mapState({
            device: state => state.app.device
        })
    }
}
</script>
<style lang="scss" scoped>
.home{
    p{
        text-align: center;
        font-size: $font_large_s;
        font-weight: 500;
        padding-top: 15%;
        @include font_color($font-color-light);
    }
}
</style>


